import{_ as a,c as e,o as i,O as t}from"./chunks/framework.0e32c9c5.js";const m=JSON.parse('{"title":"设计模式","description":"","frontmatter":{},"headers":[],"relativePath":"design-mode/index.md","filePath":"design-mode/index.md","lastUpdated":1683556564000}'),l={name:"design-mode/index.md"},o=t('<h1 id="设计模式" tabindex="-1">设计模式 <a class="header-anchor" href="#设计模式" aria-label="Permalink to &quot;设计模式&quot;">​</a></h1><h2 id="设计原则与思想-面向对象" tabindex="-1">设计原则与思想：面向对象 <a class="header-anchor" href="#设计原则与思想-面向对象" aria-label="Permalink to &quot;设计原则与思想：面向对象&quot;">​</a></h2><p>面向的对象的四大特性：</p><ul><li>封装：封装也叫作信息隐藏或者数据访问保护。类通过暴露有限的访问接口，授权外部仅能通过类提供的方式（或者叫函数）来访问内部信息或者数据</li><li>抽象：抽象讲的是如何隐藏方法的具体实现，让调用者只需要关心方法提供了哪些功能，并不需要知道这些功能是如何实现的。</li><li>继承</li><li>多态：多态是指，子类可以替换父类，在实际的代码运行过程中，调用子类的方法实现</li></ul><p>接口和抽象类的区别</p><ul><li>接口不能包含属性（也就是成员变量）。</li><li>接口只能声明方法，方法不能包含代码实现。</li><li>类实现接口的时候，必须实现接口中声明的所有方法。</li><li>抽象类不允许被实例化，只能被继承。也就是说，你不能 new 一个抽象类的对象出来（Logger logger = new Logger(...); 会报编译错误）。</li><li>抽象类可以包含属性和方法。</li><li>子类继承抽象类，必须实现抽象类中的所有抽象方法</li></ul><h2 id="创建型模式" tabindex="-1">创建型模式 <a class="header-anchor" href="#创建型模式" aria-label="Permalink to &quot;创建型模式&quot;">​</a></h2><p>用于描述&quot;怎样创建对象&quot;，它的主要特点是&quot;将对象的创建与使用分离&quot;。GOF（四人组）书中提供了单例、原型、工厂方法、抽象工厂、建造者等 5 种创建型模式。</p><h3 id="单例模式" tabindex="-1">单例模式 <a class="header-anchor" href="#单例模式" aria-label="Permalink to &quot;单例模式&quot;">​</a></h3><p>定义：保证一个类仅有一个实例，并提供全局访问的途径。</p><h2 id="结构型模式" tabindex="-1">结构型模式 <a class="header-anchor" href="#结构型模式" aria-label="Permalink to &quot;结构型模式&quot;">​</a></h2><h2 id="行为型模式" tabindex="-1">行为型模式 <a class="header-anchor" href="#行为型模式" aria-label="Permalink to &quot;行为型模式&quot;">​</a></h2>',12),r=[o];function n(d,s,h,c,_,u){return i(),e("div",null,r)}const q=a(l,[["render",n]]);export{m as __pageData,q as default};
